// PEJABAT (Lurah / Camat)
// ============================================================
func (q *Queries) ListPejabat(ctx context.Context) ([]Pejabat, error) {
	rows, err := q.db.QueryContext(ctx, listPejabat)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Pejabat{}
	for rows.Next() {
		var i Pejabat
		if err := rows.Scan(
			&i.ID,
			&i.Jabatan,
			&i.Nama,
			&i.Nip,
			&i.Aktif,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

