const nextUrutan = `-- name: NextUrutan :one

SELECT COALESCE(MAX(urutan), 0) + 1 AS next_urutan
FROM berkas_waris
WHERE tahun = ?
`

// ============================================================
// BERKAS WARIS + anak-anaknya
// ============================================================
func (q *Queries) NextUrutan(ctx context.Context, tahun int64) (int64, error) {
	row := q.db.QueryRowContext(ctx, nextUrutan, tahun)
	var next_urutan int64
	err := row.Scan(&next_urutan)
	return next_urutan, err
}

const searchBerkas = `-- name: SearchBerkas :many
SELECT b.id, b.tahun, b.urutan, b.reg_no_camat, b.reg_no_lurah, b.tanggal_reg_camat, b.tanggal_reg_lurah,
       b.tanggal_surat, b.tempat_tinggal_pewaris, b.penerima_kuasa_ahli_waris_id, b.status,
       b.created_by, b.created_at, b.updated_at
FROM berkas_waris b
WHERE EXISTS (
    SELECT 1 FROM pewaris p
    WHERE p.berkas_id = b.id
      AND (p.nama LIKE '%' || ?1 || '%' OR p.nik LIKE '%' || ?1 || '%')
)
OR b.reg_no_camat LIKE '%' || ?1 || '%'
OR b.reg_no_lurah LIKE '%' || ?1 || '%'
ORDER BY b.created_at DESC
`

func (q *Queries) SearchBerkas(ctx context.Context, dollar_1 sql.NullString) ([]BerkasWaris, error) {
	rows, err := q.db.QueryContext(ctx, searchBerkas, dollar_1)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []BerkasWaris{}
	for rows.Next() {
		var i BerkasWaris
		if err := rows.Scan(
			&i.ID,
			&i.Tahun,
			&i.Urutan,
			&i.RegNoCamat,
			&i.RegNoLurah,
			&i.TanggalRegCamat,
			&i.TanggalRegLurah,
			&i.TanggalSurat,
			&i.TempatTinggalPewaris,
			&i.PenerimaKuasaAhliWarisID,
			&i.Status,
			&i.CreatedBy,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

